insert into public.cases
  (id, groups, module, impl, title, feature, precond, data, steps, expected, warn, flag, sort)
values
  ('CORP-E2E-01', array['corp'], 'MF+Worker', 'impl', 'Baja manual de SellerMarketplace вҶ’ el worker restaura la integraciГіn (~10 min)', 'E2E worker + tracking + reconciliaciГіn', 'Usuario corporativo con integraciГіn activa (ej. FrГЎvega). Acceso a la DB.', 'Borrar la row de SellerMarketplace (FrГЎvega) В· esperar el ciclo del worker (300s) hasta 2 vueltas', '["Loguearse (aecom-test@yopmail.com) y ver Panel de Integraciones con FrГЎvega + Cetrogar en Integrado.","Eliminar en la DB la row SellerMarketplace de FrГЎvega. Refrescar: FrГЎvega vuelve a Disponible.","Esperar ~10 min (ciclos del worker). Refrescar."]'::jsonb, '["Tras la baja, FrГЎvega aparece Disponible (integraciГіn perdida).","El worker detecta un envГӯo del seller bajo el contrato de FrГЎvega vГӯa tracking hub y re-inserta/reactiva la relaciГіn.","La integraciГіn vuelve a Integrado sin intervenciГіn manual. (Evidencia 07-2026: restaurГі a los 10 min.)"]'::jsonb, null, true, 0),
  ('MF-AUTH-01-CORP', array['corp'], 'MF', 'impl', 'Bootstrap recibe auth y decide vista (Marketplace vs Seller)', 'Bootstrap / auth (src/bootstrap/App.tsx)', 'MF montado por un shell (o harness standalone) con prop auth vГЎlida.', 'auth.marketplaceId truthy вҶ’ Marketplace В· null/"" вҶ’ Seller', '["Montar con auth.marketplaceId presente.","Repetir con auth.marketplaceId null/vacГӯo."]'::jsonb, '["Con marketplaceId вҶ’ MarketplacePage (data-testid=\"marketplace-app\").","Sin marketplaceId вҶ’ SellerPage (data-testid=\"seller-app\").","En ambos, localStorage[\"fullcommerce:token\"] queda con auth.token.token."]'::jsonb, null, false, 1),
  ('MF-AUTH-01-PYME', array['pyme'], 'MF', 'impl', 'Bootstrap recibe auth y decide vista (Marketplace vs Seller)', 'Bootstrap / auth (src/bootstrap/App.tsx)', 'MF montado por un shell (o harness standalone) con prop auth vГЎlida.', 'auth.marketplaceId truthy вҶ’ Marketplace В· null/"" вҶ’ Seller', '["Montar con auth.marketplaceId presente.","Repetir con auth.marketplaceId null/vacГӯo."]'::jsonb, '["Con marketplaceId вҶ’ MarketplacePage (data-testid=\"marketplace-app\").","Sin marketplaceId вҶ’ SellerPage (data-testid=\"seller-app\").","En ambos, localStorage[\"fullcommerce:token\"] queda con auth.token.token."]'::jsonb, null, false, 2),
  ('MF-SELLERS-01', array['corp'], 'MF', 'impl', 'Grilla de sellers carga desde API', 'Marketplace Sellers grid', 'Vista Marketplace В· token REST vГЎlido В· API arriba.', 'GET /api/v1/Marketplace/sellers?Page=1&PageSize=10', '["Entrar como marketplace y abrir vista Sellers (KPI \"Sellers totales\").","Observar la request."]'::jsonb, '["Loading: fila con CircularProgress.","Success: filas con nombre + estado (Pills) + paginaciГіn server.","Empty: \"No hay sellers para mostrar.\"","Error: \"No pudimos cargar los sellers. Intenta nuevamente.\""]'::jsonb, null, false, 3),
  ('MF-SELLERS-02', array['corp'], 'MF', 'impl', 'Filtro por estado (Activa / Inactiva)', 'Marketplace Sellers grid', 'Grilla cargada.', 'Status=Activa / Status=Inactiva', '["Seleccionar filtro Activa.","Seleccionar Inactiva."]'::jsonb, '["La request incluye Status y refetchea con overlay de loading.","Solo se muestran sellers del estado elegido."]'::jsonb, null, false, 4),
  ('MF-SELLERS-03', array['corp'], 'MF', 'impl', 'BГәsqueda + paginaciГіn + page size', 'Marketplace Sellers grid', 'Grilla con mГЎs de una pГЎgina.', 'Page size 5 / 10 / 20', '["Buscar un fragmento de nombre/email.","Cambiar page size (5вҶ’20).","Navegar entre pГЎginas."]'::jsonb, '["BГәsqueda filtra CLIENT-SIDE sobre la pГЎgina cargada (el server no tiene param Search).","Cambiar page size dispara nueva request.","PaginaciГіn avanza/retrocede."]'::jsonb, 'Quirk conocido: durante la bГәsqueda el count de paginaciГіn usa solo el largo filtrado.', false, 5),
