  ('MF-SHIP-01', array['corp'], 'MF', 'impl', 'Grilla de envГӯos vГӯa SignalR', 'MarketplaceSellerShipments.tsx', 'Branch NTGRCNS-562 В· token LARGO B2C en localStorage["token"] В· hub de tracking accesible.', 'Hub TrackingSubscribeState В· evento sendTracking В· seller pruebacorpo24 (94 envГӯos) В· userId="" В· 30 dГӯas', '["Abrir la vista de envГӯos de un seller.","Observar: WebSocket (skipNegotiation) вҶ’ send вҶ’ sendTracking.","Cambiar el rango Desde."]'::jsonb, '["Conecta por WebSockets directo (sin negotiate).","Muestra hasta 50 filas (cap del hub) + aviso \"Mostrando N de M\".","Cambiar fecha resetea a pГЎgina 0 y re-suscribe.","userId debe ir VACГҚO (el GUID no mapea en el elastic de tracking)."]'::jsonb, 'Vive solo en branch NTGRCNS-562 (PR #25, draft). No estГЎ en develop.', false, 12),
  ('MF-SHIP-02', array['corp'], 'MF', 'impl', 'Estados UX de la grilla de envГӯos (loading / empty / timeout)', 'Grilla de envГӯos вҖ” estados', 'Igual que MF-SHIP-01.', 'Timeout de respuesta (default de useHubSubscription)', '["Cargar con conexiГіn OK pero sin datos (seller sin envГӯos en la ventana).","Cortar red tras conectar para gatillar el timeout."]'::jsonb, '["Loading: \"Recuperando envГӯos\".","Empty: mensaje de sin resultados.","Timeout: banner de error (por timeout, no por rechazo de send).","Sin flashes ni doble-suscripciГіn al reconectar."]'::jsonb, 'Vive solo en branch NTGRCNS-562.', false, 13),
