  ('API-CONTRACTS-01', array['otros'], 'API', 'nofront', 'Contratos del seller por email', 'GET /seller-contracts', 'вҖ”', 'GET /seller-contracts?Email', '["GET con Email vГЎlido.","GET sin Email."]'::jsonb, '["Por cada marketplace activo: MarketplaceEmail + lista de contratos.","Email faltante вҶ’ 400."]'::jsonb, 'Sin consumidor front. Alimenta la misma lГіgica que replica el worker.', false, 30),
