  ('WK-SYNC-01', array['otros'], 'Worker', 'impl', 'Arranque y loop periГіdico', 'SellerSynchronizationWorker', '.NET 10 В· DB de prueba В· Worker:ExecutionIntervalSeconds (ej. 5s).', 'dotnet run --project src/Api/ActualizacionSellersWorker.csproj', '["Levantar con intervalo corto.","Observar logs + APM."]'::jsonb, '["Log de deployment marker al iniciar.","Cada iteraciГіn abre transacciГіn APM seller-synchronization y loguea el resumen.","Intervalo вүӨ0 вҶ’ excepciГіn de config."]'::jsonb, null, false, 32),
  ('WK-SYNC-02', array['otros'], 'Worker', 'impl', 'Carga de contratos activos (Contract вӢҲ Marketplace)', 'GetActiveContracts', 'DB con Contract + Marketplace.', 'c.IsDeleted=0 AND m.IsActive=1 AND m.IsDeleted=0', '["Insertar 1 contrato activo + 1 borrado.","Correr una iteraciГіn."]'::jsonb, '["Solo el activo entra al procesamiento.","Ventana: to=now, from=now - ActiveSellerLookbackDays (default 30)."]'::jsonb, null, false, 33),
  ('WK-SYNC-03', array['otros'], 'Worker', 'impl', 'Consulta al hub de tracking por contrato', 'TrackingSuscribeStateByContrato', 'Hub accesible (Tracking:HubUrl).', '{idSistema:4, idReceptor:2, contrato, from, to, esActivo:true} В· evento SendTrackingByContrato', '["Con un contrato con envГӯos en la ventana, correr iteraciГіn.","Observar suscripciГіn y respuesta."]'::jsonb, '["Recibe resultsList; mapea emailвҶ’MarketplaceEmail, fechaPrimeraNovedadвҶ’LastShipment.","Items con email vacГӯo se descartan.","Dedup por (ContractNo, MarketplaceEmail) con el LastShipment mГЎs reciente.","Fallo del hub вҶ’ contrato cuenta como failed, el loop sigue."]'::jsonb, null, false, 34),
  ('WK-SYNC-04', array['otros'], 'Worker', 'impl', 'Alta de relaciГіn Seller-Marketplace nueva', 'SellerMarketplaceReconciler', 'Tracking devuelve un seller sin relaciГіn con ese marketplace.', 'Login API POST /api/v1/Usuario/Email para resolver nombre/CL/tipo', '["Preparar tracking con seller nuevo.","Correr iteraciГіn."]'::jsonb, '["Resuelve el Seller (por email; si no, reactiva soft-deleted; si no, Login API + insert).","Corporate sin CL resoluble вҶ’ se saltea.","Inserta/reactiva SellerMarketplace вҶ’ Registered.","Emails normalizados Trim().ToLowerInvariant()."]'::jsonb, null, false, 35),
  ('WK-SYNC-05', array['otros'], 'Worker', 'impl', 'Update de LastShipment (envГӯo mГЎs reciente)', 'UpdateLastShipment (condicional)', 'Existe SellerMarketplace activo con LastShipment viejo.', 'Tracking con envГӯo mГЎs reciente / mГЎs viejo', '["EnvГӯo mГЎs nuevo вҶ’ correr iteraciГіn.","Repetir con envГӯo mГЎs viejo."]'::jsonb, '["MГЎs nuevo вҶ’ UPDATE condicional de LastShipment вҶ’ Updated; si Name vacГӯo, SellerNameEnricher lo completa (best-effort).","MГЎs viejo вҶ’ SkippedOlderShipment (no actualiza)."]'::jsonb, null, false, 36),
  ('WK-SYNC-06', array['otros'], 'Worker', 'impl', 'Fallback a PendingSellerMarketplace', 'UpsertPendingSellerMarketplace', 'Seller no resoluble o relaciГіn ya activa.', 'вҖ”', '["Forzar un seller no resoluble (corporate sin CL) o relaciГіn ya activa.","Correr iteraciГіn."]'::jsonb, '["Upsert en PendingSellerMarketplace (insert o update de LastShipment) вҶ’ QueuedToPending.","No rompe el resto del procesamiento."]'::jsonb, null, false, 37)
